            WriteLiteral(@"

<script>

    function decrement(id, price, isFromSlidingCart) {
        var quantity = parseInt($('#qty_' + id + '').val());
        if (quantity > 0) {
            $('#qty_' + id + '').val(quantity - 1);
        }
        orderEntry.changeItemQty(id, price, isFromSlidingCart);
    }

    function increment(id, price, isFromSlidingCart) {
        var quantity = parseInt($('#qty_' + id + '').val());
        $('#qty_' + id + '').val(quantity + 1);
        orderEntry.changeItemQty(id, price, isFromSlidingCart);
    }
</script>");
        }
